function solve(nums: number[], k: number): number {
    let totalSum = nums.reduce((a, b) => a + b, 0);
    const n = nums.length;
    const prefixSums = new Array(n + 1).fill(0);
    for (let i = 1; i <= n; i++) {
        prefixSums[i] = prefixSums[i - 1] + nums[i - 1];
    }

    let dpPrev = 0;
    const modMap = new Map<number, number>();
    modMap.set(0, 0);

    for (let i = 1; i <= n; i++) {
        const currentS = prefixSums[i];
        const mod = currentS % k;
        let currentMax = -Infinity;
        if (modMap.has(mod)) {
            currentMax = modMap.get(mod)! + currentS;
        }
        const dpCurrent = Math.max(dpPrev, currentMax);

        // Update modMap for current mod
        const valueToStore = dpCurrent - currentS;
        if (modMap.has(mod)) {
            modMap.set(mod, Math.max(modMap.get(mod)! , valueToStore));
        } else {
            modMap.set(mod, valueToStore);
        }

        dpPrev = dpCurrent;
    }

    return totalSum - dpPrev;
}
