    let s = 0;
    const modMap = new Map<number, number>();
    modMap.set(0, 0);
    let dpPrev = 0;

    for (const num of nums) {
        s += num;
        const currentMod = s % k;
        const maxPrev = modMap.get(currentMod) || -Infinity;
        const candidate = maxPrev + s;
        const currentDP = Math.max(dpPrev, candidate);

        const currentValue = currentDP - s;
        if (modMap.has(currentMod)) {
            if (currentValue > modMap.get(currentMod)!) {
                modMap.set(currentMod, currentValue);
            }
        } else {
            modMap.set(currentMod, currentValue);
        }

        dpPrev = currentDP;
    }

    return s - dpPrev;
}
